import { useState } from "react";
import "./index.css";

const initialTasks = [
  { id: 1, name: "Оновити ядро Arch Linux", completed: true },
  { id: 2, name: "Налаштувати кольори Waybar", completed: false },
  { id: 3, name: "Зробити бекап дотфайлів", completed: false },
];

export default function TaskManeger() {
  return (
    <div className="app-container">
      <h1>Менеджер завдань</h1>
      <div className="task-list">
        {initialTasks.map((task) => (
          <div
            key={task.id}
            className={task.completed ? "task done" : "task pending"}
          >
            <p>{task.name}</p>
          </div>
        ))}
      </div>
    </div>
  );
}
